                             {
                                 try { System.IO.File.Delete(oldFilePath); } catch { }
                             }
                         }
                         using (var stream = System.IO.File.Create(filePath))
                         {
                             teachingMaterialImage.CopyTo(stream);
                         }
                         course.TeachingMaterialImagePath = $"/Uploads/TeachingMaterials/{fileName}";
                     }
                     catch (Exception ex)
                     {
