using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.TestHelpers
{
    public static class TestDbContextFactory
    {
        public static SchoolContext Create(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;

            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }

        public static SchoolContext CreateWithSeedData(string dbName = null)
        {
            var context = Create(dbName);
            SeedData(context);
            return context;
        }

        private static void SeedData(SchoolContext context)
        {
            var instructors = new[]
            {
                new Instructor { ID = 1, LastName = "Smith", FirstMidName = "John", HireDate = new DateTime(2010, 1, 1) },
                new Instructor { ID = 2, LastName = "Johnson", FirstMidName = "Jane", HireDate = new DateTime(2012, 6, 15) },
                new Instructor { ID = 3, LastName = "Williams", FirstMidName = "Robert", HireDate = new DateTime(2015, 9, 1) }
            };
            context.Instructors.AddRange(instructors);

            var departments = new[]
            {
                new Department { DepartmentID = 1, Name = "Computer Science", Budget = 100000m, StartDate = new DateTime(2000, 1, 1), InstructorID = 1 },
                new Department { DepartmentID = 2, Name = "Mathematics", Budget = 80000m, StartDate = new DateTime(2001, 1, 1), InstructorID = 2 },
                new Department { DepartmentID = 3, Name = "Physics", Budget = 90000m, StartDate = new DateTime(2002, 1, 1), InstructorID = 3 }
            };
            context.Departments.AddRange(departments);

            var courses = new[]
            {
                new Course { CourseID = 1001, Title = "Intro to CS", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 1002, Title = "Data Structures", Credits = 4, DepartmentID = 1 },
                new Course { CourseID = 2001, Title = "Calculus I", Credits = 4, DepartmentID = 2 },
                new Course { CourseID = 3001, Title = "Quantum Mechanics", Credits = 3, DepartmentID = 3 }
            };
            context.Courses.AddRange(courses);

            var students = new[]
            {
                new Student { ID = 10, LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { ID = 11, LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { ID = 12, LastName = "Baker", FirstMidName = "Arturo", EnrollmentDate = new DateTime(2021, 1, 15) },
                new Student { ID = 13, LastName = "Zhao", FirstMidName = "Lily", EnrollmentDate = new DateTime(2021, 9, 1) },
                new Student { ID = 14, LastName = "Norman", FirstMidName = "Nino", EnrollmentDate = new DateTime(2022, 1, 10) }
            };
            context.Students.AddRange(students);

            var enrollments = new[]
            {
                new Enrollment { EnrollmentID = 1, CourseID = 1001, StudentID = 10, Grade = Grade.A },
                new Enrollment { EnrollmentID = 2, CourseID = 1002, StudentID = 10, Grade = Grade.B },
                new Enrollment { EnrollmentID = 3, CourseID = 2001, StudentID = 11, Grade = Grade.C },
                new Enrollment { EnrollmentID = 4, CourseID = 1001, StudentID = 12, Grade = null },
                new Enrollment { EnrollmentID = 5, CourseID = 3001, StudentID = 13, Grade = Grade.A }
            };
            context.Enrollments.AddRange(enrollments);

            var courseAssignments = new[]
            {
                new CourseAssignment { InstructorID = 1, CourseID = 1001 },
                new CourseAssignment { InstructorID = 1, CourseID = 1002 },
                new CourseAssignment { InstructorID = 2, CourseID = 2001 },
                new CourseAssignment { InstructorID = 3, CourseID = 3001 }
            };
            context.CourseAssignments.AddRange(courseAssignments);

            var officeAssignments = new[]
            {
                new OfficeAssignment { InstructorID = 1, Location = "Room 101" },
                new OfficeAssignment { InstructorID = 2, Location = "Room 202" }
            };
            context.OfficeAssignments.AddRange(officeAssignments);

            context.SaveChanges();
        }
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.TestHelpers;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewResult_WithPaginatedList()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(5, model.Count);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Alexander", model.First().LastName);
            Assert.Equal("Zhao", model.Last().LastName);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Zhao", model.First().LastName);
            Assert.Equal("Alexander", model.Last().LastName);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(new DateTime(2020, 9, 1), model.First().EnrollmentDate);
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(new DateTime(2022, 1, 10), model.First().EnrollmentDate);
        }

        [Fact]
        public void Index_SearchByLastName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Carson", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Carson", model.First().FirstMidName);
        }

        [Fact]
        public void Index_SearchString_ResetsPageToOne()
        {
            var result = _controller.Index(null, null, "Alexander", 3) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Baker", null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Baker", model.First().LastName);
        }

        [Fact]
        public void Index_SetsViewBagProperties()
        {
            var result = _controller.Index("Date", null, "test", null) as ViewResult;

            Assert.Equal("Date", result.ViewData["CurrentSort"]);
            Assert.Equal("date_desc", result.ViewData["DateSortParm"]);
            Assert.Equal("", result.ViewData["NameSortParm"]);
            Assert.Equal("test", result.ViewData["CurrentFilter"]);
        }

        [Fact]
        public void Index_EmptySortOrder_SetsNameSortParmToDesc()
        {
            var result = _controller.Index("", null, null, null) as ViewResult;

            Assert.Equal("name_desc", result.ViewData["NameSortParm"]);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Details(10) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
            Assert.Equal("Carson", student.FirstMidName);
        }

        [Fact]
        public void Details_ValidId_IncludesEnrollments()
        {
            var result = _controller.Details(10) as ViewResult;

            var student = Assert.IsType<Student>(result.Model);
            Assert.NotNull(student.Enrollments);
            Assert.Equal(2, student.Enrollments.Count);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_Get_ReturnsViewWithStudentDefaultDate()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, student.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_Post_ValidStudent_AddsToDatabase()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            _controller.Create(student);

            Assert.Equal(6, _context.Students.Count());
            Assert.Contains(_context.Students, s => s.LastName == "NewStudent");
        }

        [Fact]
        public void Create_Post_MinDateEnrollment_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Invalid",
                FirstMidName = "Date",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_Post_DateBeforeSqlMin_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Invalid",
                FirstMidName = "Date",
                EnrollmentDate = new DateTime(1752, 12, 31)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsViewWithStudent()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal(student, result.Model);
        }

        #endregion

        #region Edit Tests

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Edit(10) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            var student = _context.Students.Find(10);
            student.LastName = "UpdatedName";

            // Detach and re-attach for edit
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_MinDateEnrollment_AddsModelError()
        {
            var student = new Student
            {
                ID = 10,
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = DateTime.MinValue
            };

            _context.Entry(_context.Students.Find(10)).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 10,
                LastName = "",
                FirstMidName = "Carson",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal(student, result.Model);
        }

        #endregion

        #region Delete Tests

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Delete(10) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesStudentAndRedirects()
        {
            var result = _controller.DeleteConfirmed(10) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(4, _context.Students.Count());
            Assert.Null(_context.Students.Find(10));
        }

        #endregion
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.TestHelpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.IO;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempWebRoot;

        public CoursesControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _tempWebRoot = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempWebRoot);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempWebRoot);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempWebRoot);
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller?.Dispose();
            _context?.Dispose();
            if (Directory.Exists(_tempWebRoot))
                Directory.Delete(_tempWebRoot, true);
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewWithAllCourses()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(result.Model);
            Assert.Equal(4, model.Count);
        }

        [Fact]
        public void Index_IncludesDepartment()
        {
            var result = _controller.Index() as ViewResult;

            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(result.Model);
            Assert.All(model, c => Assert.NotNull(c.Department));
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Details(1001) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Intro to CS", course.Title);
            Assert.NotNull(course.Department);
        }

        #endregion

        #region Create Tests

