using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any existing notifications from the static queue
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service?.Dispose();
        }

        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage()
        {
            _service.SendNotification("Student", "1", "John Smith", EntityOperation.CREATE, "admin");

            var notification = _service.ReceiveNotification();
            Assert.Equal("New Student 'John Smith' has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Course", "101", EntityOperation.UPDATE, "admin");

            var notification = _service.ReceiveNotification();
            Assert.Equal("Course (ID: 101) has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_GeneratesUpdateMessage()
        {
            _service.SendNotification("Department", "5", "Math", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("Department 'Math' has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesDeleteMessage()
        {
            _service.SendNotification("Instructor", "3", "Jane Doe", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("Instructor 'Jane Doe' has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var result = _service.ReceiveNotification();

            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
        {
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);
            _service.SendNotification("C", "3", EntityOperation.DELETE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();

            Assert.Equal("A", first.EntityType);
            Assert.Equal("B", second.EntityType);
            Assert.Equal("C", third.EntityType);
        }

        [Fact]
        public void ReceiveNotification_DequeuesMessage()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.NotNull(first);
            Assert.Null(second);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory, but should not throw
            var ex = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(ex);
        }

        [Fact]
        public void SendNotification_OverloadWithoutDisplayName_Works()
        {
            _service.SendNotification("Test", "42", EntityOperation.CREATE, "user1");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Test", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var ex = Record.Exception(() => service.Dispose());
            Assert.Null(ex);
        }
    }
}

using System;
