        [Fact]
        public void DeleteConfirmed_WithImage_DeletesFileAndRemovesCourse()
        {
            // Set up a course with an image path
            var course = _context.Courses.Find(1002);
            var uploadsDir = Path.Combine(_tempWebRoot, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsDir);
            var imageFile = Path.Combine(uploadsDir, "test_image.jpg");
            File.WriteAllText(imageFile, "fake image");
            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
            _context.SaveChanges();

            var result = _controller.DeleteConfirmed(1002) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.False(File.Exists(imageFile));
        }

        #endregion

        private Mock<IFormFile> CreateMockFormFile(string fileName, string content, long length)
        {
            var mockFile = new Mock<IFormFile>();
            var ms = new MemoryStream(System.Text.Encoding.UTF8.GetBytes(content));
            mockFile.Setup(f => f.FileName).Returns(fileName);
            mockFile.Setup(f => f.Length).Returns(length);
            mockFile.Setup(f => f.OpenReadStream()).Returns(ms);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(s => ms.CopyTo(s));
            return mockFile;
        }
    }
