using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.TestHelpers
{
    public static class TestDbContextFactory
    {
        public static SchoolContext Create(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;

            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }

        public static SchoolContext CreateWithSeedData(string dbName = null)
        {
            var context = Create(dbName);
            SeedData(context);
            return context;
        }

        private static void SeedData(SchoolContext context)
        {
            var instructors = new[]
            {
                new Instructor { ID = 1, LastName = "Smith", FirstMidName = "John", HireDate = new DateTime(2010, 1, 1) },
                new Instructor { ID = 2, LastName = "Johnson", FirstMidName = "Jane", HireDate = new DateTime(2012, 6, 15) },
                new Instructor { ID = 3, LastName = "Williams", FirstMidName = "Robert", HireDate = new DateTime(2015, 9, 1) }
            };
            context.Instructors.AddRange(instructors);

            var departments = new[]
            {
                new Department { DepartmentID = 1, Name = "Computer Science", Budget = 100000m, StartDate = new DateTime(2000, 1, 1), InstructorID = 1 },
                new Department { DepartmentID = 2, Name = "Mathematics", Budget = 80000m, StartDate = new DateTime(2001, 1, 1), InstructorID = 2 },
                new Department { DepartmentID = 3, Name = "Physics", Budget = 90000m, StartDate = new DateTime(2002, 1, 1), InstructorID = 3 }
            };
            context.Departments.AddRange(departments);

            var courses = new[]
            {
                new Course { CourseID = 1001, Title = "Intro to CS", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 1002, Title = "Data Structures", Credits = 4, DepartmentID = 1 },
                new Course { CourseID = 2001, Title = "Calculus I", Credits = 4, DepartmentID = 2 },
                new Course { CourseID = 3001, Title = "Quantum Mechanics", Credits = 3, DepartmentID = 3 }
            };
            context.Courses.AddRange(courses);

            var students = new[]
            {
                new Student { ID = 10, LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { ID = 11, LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { ID = 12, LastName = "Baker", FirstMidName = "Arturo", EnrollmentDate = new DateTime(2021, 1, 15) },
                new Student { ID = 13, LastName = "Zhao", FirstMidName = "Lily", EnrollmentDate = new DateTime(2021, 9, 1) },
                new Student { ID = 14, LastName = "Norman", FirstMidName = "Nino", EnrollmentDate = new DateTime(2022, 1, 10) }
            };
            context.Students.AddRange(students);

            var enrollments = new[]
            {
                new Enrollment { EnrollmentID = 1, CourseID = 1001, StudentID = 10, Grade = Grade.A },
                new Enrollment { EnrollmentID = 2, CourseID = 1002, StudentID = 10, Grade = Grade.B },
                new Enrollment { EnrollmentID = 3, CourseID = 2001, StudentID = 11, Grade = Grade.C },
                new Enrollment { EnrollmentID = 4, CourseID = 1001, StudentID = 12, Grade = null },
                new Enrollment { EnrollmentID = 5, CourseID = 3001, StudentID = 13, Grade = Grade.A }
            };
            context.Enrollments.AddRange(enrollments);

            var courseAssignments = new[]
            {
