using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.TestHelpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.IO;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempWebRoot;

        public CoursesControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _tempWebRoot = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempWebRoot);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempWebRoot);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempWebRoot);
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller?.Dispose();
            _context?.Dispose();
            if (Directory.Exists(_tempWebRoot))
                Directory.Delete(_tempWebRoot, true);
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewWithAllCourses()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(result.Model);
            Assert.Equal(4, model.Count);
        }

        [Fact]
        public void Index_IncludesDepartment()
        {
            var result = _controller.Index() as ViewResult;

            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(result.Model);
            Assert.All(model, c => Assert.NotNull(c.Department));
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Details(1001) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Intro to CS", course.Title);
            Assert.NotNull(course.Department);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_Get_ReturnsViewWithDepartmentSelectList()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(result.ViewData["DepartmentID"]);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal(0, model.CourseID);
        }

        [Fact]
        public void Create_Post_ValidCourse_NoImage_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 5001,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Contains(_context.Courses, c => c.CourseID == 5001);
        }

        [Fact]
        public void Create_Post_ValidCourse_WithValidImage_UploadsFile()
        {
            var course = new Course
            {
                CourseID = 5002,
                Title = "Course With Image",
                Credits = 4,
                DepartmentID = 1
            };

            var mockFile = CreateMockFormFile("test.jpg", "image content", 1024);

            var result = _controller.Create(course, mockFile.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            var savedCourse = _context.Courses.Find(5002);
            Assert.NotNull(savedCourse.TeachingMaterialImagePath);
            Assert.StartsWith("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_InvalidFileExtension_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 5003,
                Title = "Bad Image",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = CreateMockFormFile("test.exe", "bad content", 1024);

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_FileTooLarge_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 5004,
                Title = "Large Image",
                Credits = 3,
                DepartmentID = 1
