using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.TestHelpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _controller = new DepartmentsController(_context);
        }

        public void Dispose()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewWithAllDepartments()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_IncludesAdministrator()
        {
            var result = _controller.Index() as ViewResult;

            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(result.Model);
            Assert.All(model, d => Assert.NotNull(d.Administrator));
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal("Computer Science", department.Name);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_Get_ReturnsViewWithInstructorSelectList()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(result.ViewData["InstructorID"]);
        }

        [Fact]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            var department = new Department
            {
                Name = "New Department",
                Budget = 50000m,
                StartDate = new DateTime(2023, 1, 1),
                InstructorID = 1
            };

            var result = _controller.Create(department) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_Post_ValidDepartment_AddsToDatabase()
        {
            var department = new Department
            {
                Name = "History",
                Budget = 60000m,
                StartDate = new DateTime(2023, 1, 1),
                InstructorID = 2
            };

            _controller.Create(department);

            Assert.Equal(4, _context.Departments.Count());
            Assert.Contains(_context.Departments, d => d.Name == "History");
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsViewWithSelectList()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department { Budget = 50000m };

            var result = _controller.Create(department) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(result.ViewData["InstructorID"]);
        }

        #endregion

        #region Edit Tests

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithDepartment()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal("Computer Science", department.Name);
            Assert.NotNull(result.ViewData["InstructorID"]);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            var department = new Department
            {
                DepartmentID = 1,
                Name = "Updated CS",
                Budget = 120000m,
                StartDate = new DateTime(2000, 1, 1),
                InstructorID = 1
            };

            _context.Entry(_context.Departments.Find(1)).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(department) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsViewWithSelectList()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department
            {
                DepartmentID = 1,
                Name = "",
                Budget = 100000m,
                StartDate = new DateTime(2000, 1, 1),
                InstructorID = 1
            };

            var result = _controller.Edit(department) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(result.ViewData["InstructorID"]);
        }

        #endregion

        #region Delete Tests

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithDepartment()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal("Computer Science", department.Name);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesDepartmentAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(2, _context.Departments.Count());
            Assert.Null(_context.Departments.Find(1));
        }

        #endregion
    }
}

