using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.TestHelpers;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        #region Index Tests

        [Fact]
        public void Index_NoSelection_ReturnsViewWithAllInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.Equal(3, model.Instructors.Count());
        }

        [Fact]
        public void Index_InstructorsOrderedByLastName()
        {
            var result = _controller.Index(null, null) as ViewResult;

            var model = Assert.IsType<InstructorIndexData>(result.Model);
            var instructors = model.Instructors.ToList();
            Assert.Equal("Johnson", instructors[0].LastName);
            Assert.Equal("Smith", instructors[1].LastName);
            Assert.Equal("Williams", instructors[2].LastName);
        }

        [Fact]
        public void Index_WithInstructorId_ShowsCourses()
        {
            var result = _controller.Index(1, null) as ViewResult;

            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Courses);
            Assert.Equal(2, model.Courses.Count());
        }

        [Fact]
        public void Index_WithCourseId_ShowsEnrollments()
        {
            var result = _controller.Index(1, 1001) as ViewResult;

            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Enrollments);
        }

        [Fact]
        public void Index_SetsViewBagInstructorID()
        {
            var result = _controller.Index(1, null) as ViewResult;

            Assert.Equal(1, result.ViewData["InstructorID"]);
        }

        [Fact]
        public void Index_SetsViewBagCourseID()
        {
            var result = _controller.Index(1, 1001) as ViewResult;

            Assert.Equal(1001, result.ViewData["CourseID"]);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Smith", instructor.LastName);
            Assert.Equal("John", instructor.FirstMidName);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_Get_ReturnsViewWithCoursesInViewBag()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(instructor.CourseAssignments);
            Assert.NotNull(result.ViewData["Courses"]);
        }

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1)
            };

            var result = _controller.Create(instructor, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_Post_ValidInstructor_AddsToDatabase()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1)
            };

            _controller.Create(instructor, null);

            Assert.Equal(4, _context.Instructors.Count());
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AssignsCourses()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "WithCourses",
                HireDate = new DateTime(2023, 1, 1)
            };
            var selectedCourses = new[] { "1001", "2001" };

            _controller.Create(instructor, selectedCourses);

            var saved = _context.Instructors.Include(i => i.CourseAssignments)
                .Single(i => i.LastName == "NewInstructor");
            Assert.Equal(2, saved.CourseAssignments.Count);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(result.ViewData["Courses"]);
        }

        #endregion

        #region Edit Tests

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Smith", instructor.LastName);
            Assert.NotNull(result.ViewData["Courses"]);
        }

        #endregion

        #region Delete Tests

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Smith", instructor.LastName);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            var result = _controller.DeleteConfirmed(3) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(2, _context.Instructors.Count());
        }

        [Fact]
        public void DeleteConfirmed_NullsDepartmentAdministrator()
        {
            // Instructor 1 is admin of Department 1
            _controller.DeleteConfirmed(1);

            var dept = _context.Departments.Find(1);
            Assert.Null(dept.InstructorID);
        }

        #endregion
    }
}

