using ContosoUniversity.Models;
using System;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PersonTests
    {
        [Fact]
        public void FullName_ReturnsLastNameCommaFirstName()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John"
            };

            Assert.Equal("Smith, John", student.FullName);
        }

        [Fact]
        public void FullName_WorksForInstructor()
        {
            var instructor = new Instructor
            {
                LastName = "Doe",
                FirstMidName = "Jane"
            };

            Assert.Equal("Doe, Jane", instructor.FullName);
        }
    }

    public class NotificationModelTests
    {
        [Fact]
        public void Notification_DefaultIsRead_IsFalse()
        {
            var notification = new Notification();

            Assert.False(notification.IsRead);
        }

        [Fact]
        public void Notification_Properties_CanBeSet()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "10",
                Operation = "CREATE",
                Message = "Test message",
                CreatedAt = now,
                CreatedBy = "admin",
                IsRead = true,
                ReadAt = now
            };

            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("10", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("Test message", notification.Message);
            Assert.Equal(now, notification.CreatedAt);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.True(notification.IsRead);
            Assert.Equal(now, notification.ReadAt);
        }

        [Fact]
        public void EntityOperation_HasExpectedValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }
    }

    public class CourseModelTests
    {
        [Fact]
        public void Course_Properties_CanBeSet()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/path/to/image.jpg"
            };

            Assert.Equal(1001, course.CourseID);
            Assert.Equal("Test Course", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
            Assert.Equal("/path/to/image.jpg", course.TeachingMaterialImagePath);
        }
    }

    public class EnrollmentModelTests
    {
        [Fact]
        public void Enrollment_Grade_CanBeNull()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1001,
                StudentID = 10,
                Grade = null
            };

            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void Grade_HasExpectedValues()
        {
            Assert.Equal(0, (int)Grade.A);
            Assert.Equal(1, (int)Grade.B);
            Assert.Equal(2, (int)Grade.C);
            Assert.Equal(3, (int)Grade.D);
            Assert.Equal(4, (int)Grade.F);
        }
    }

    public class DepartmentModelTests
    {
        [Fact]
        public void Department_InstructorID_CanBeNull()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Test",
                Budget = 50000m,
                StartDate = DateTime.Now,
                InstructorID = null
            };

            Assert.Null(dept.InstructorID);
        }
    }

    public class OfficeAssignmentModelTests
    {
        [Fact]
        public void OfficeAssignment_Properties_CanBeSet()
        {
            var oa = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Room 101"
            };

            Assert.Equal(1, oa.InstructorID);
            Assert.Equal("Room 101", oa.Location);
        }
    }

    public class CourseAssignmentModelTests
    {
        [Fact]
        public void CourseAssignment_Properties_CanBeSet()
        {
            var ca = new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 1001
            };

            Assert.Equal(1, ca.InstructorID);
            Assert.Equal(1001, ca.CourseID);
        }
    }
}

